        "model": "gpt-5-pro",
        "input": []map[string]interface{}{
            {
                "role": "user",
                "content": []map[string]interface{}{
                    {
                        "type": "input_text",
                        "text": "Write a short poem about artificial intelligence and its impact on humanity.",
