    writer.WriteField("prompt", "She turns around and smiles, then slowly walks out of the frame.")
    writer.WriteField("size", "720x1280")
    writer.WriteField("input_reference", "sample_720p.jpeg")
    writer.WriteField("seconds", "4")

    file, _ := os.Open("sample_720p.jpeg")
    defer file.Close()
    part, _ := writer.CreateFormFile("input_reference", "sample_720p.jpeg")
    io.Copy(part, file)

    writer.Close()

    req, _ := http.NewRequest("POST", url, &body)
    req.Header.Set("Authorization", "Bearer YOUR_API_KEY")
    req.Header.Set("Content-Type", writer.FormDataContentType())

    client := &http.Client{}
    resp, err := client.Do(req)
    if err != nil {
        panic(err)
